mapper.select:
select u.user_id, u.dept_id, u.login_name, u.user_name, u.real_name, u.user_type, u.email, u.avatar, u.phonenumber, u.password, u.sex, u.salt, u.status, u.del_flag, u.login_ip, u.login_date, u.create_by, u.create_time, u.remark, d.dept_name, d.leader, (SELECT GROUP_CONCAT(DISTINCT s.company_name ORDER BY s.company_name SEPARATOR ',') FROM scm_supplier_user su INNER JOIN scm_supplier s ON su.supplier_id = s.supplier_id AND s.del_flag = '0' WHERE su.user_id = u.user_id AND su.status = '0' AND (su.del_flag = '0' OR su.del_flag IS NULL) ) AS supplier_names, (SELECT GROUP_CONCAT(DISTINCT h.hospital_name ORDER BY h.hospital_name SEPARATOR ',') FROM scm_hospital_user hu INNER JOIN scm_hospital h ON hu.hospital_id = h.hospital_id AND h.del_flag = '0' AND h.status = '0' WHERE hu.user_id = u.user_id AND hu.status = '0' AND (hu.del_flag = '0' OR hu.del_flag IS NULL) ) AS hospital_names, (SELECT GROUP_CONCAT(DISTINCT r.role_name ORDER BY r.role_sort, r.role_name SEPARATOR ',') FROM sys_user_role ur INNER JOIN sys_role r ON ur.role_id = r.role_id AND r.del_flag = '0' AND r.status = '0' WHERE ur.user_id = u.user_id ) AS role_names from sys_user u left join sys_dept d on u.dept_id = d.dept_id where u.del_flag = '0'
AND u.user_id = #{userId}
AND u.login_name like concat('%', #{loginName}, '%')
AND u.status = #{status}
AND u.phonenumber like concat('%', #{phonenumber}, '%')
AND date_format(u.create_time,'%Y%m%d') >= date_format(#{params.beginTime},'%Y%m%d')
AND date_format(u.create_time,'%Y%m%d') <= date_format(#{params.endTime},'%Y%m%d')
AND (u.dept_id = #{deptId} OR u.dept_id IN ( SELECT t.dept_id FROM sys_dept t WHERE FIND_IN_SET (#{deptId},ancestors) ))
${params.dataScope}
${params.tenantScope}

    select distinct u.user_id, u.dept_id, u.login_name, u.user_name, u.real_name, u.user_type, u.email, u.avatar, u.phonenumber, u.status, u.create_time
    from sys_user u
		 left join sys_dept d on u.dept_id = d.dept_id
		 left join sys_user_role ur on u.user_id = ur.user_id
		 left join sys_role r on r.role_id = ur.role_id
    where u.del_flag = '0' and r.role_id = #{roleId}

		AND u.login_name like concat('%', #{loginName}, '%')


		AND u.phonenumber like concat('%', #{phonenumber}, '%')


	${params.dataScope}
	${params.tenantScope}

mapper.update:
update sys_user
dept_id = #{deptId}, login_name = #{loginName}, user_name = #{userName}, real_name = #{realName}, user_type = #{userType}, email = #{email}, phonenumber = #{phonenumber}, sex = #{sex}, avatar = #{avatar}, password = #{password}, salt = #{salt}, status = #{status}, login_ip = #{loginIp}, login_date = #{loginDate}, pwd_update_date = #{pwdUpdateDate}, update_by = #{updateBy}, remark = #{remark}, update_time = sysdate()
where user_id = #{userId}
